package main
// Echo Service Monitor (EN)
import ("fmt";"math/rand";"net/http";"os";"time";"github.com/labstack/echo/v4";"github.com/labstack/echo/v4/middleware")
var startTime = time.Now()
func main() {
	e := echo.New(); e.HideBanner = true; e.Use(middleware.Logger())
	e.GET("/", func(c echo.Context) error { return c.HTML(http.StatusOK, dash()) })
	e.GET("/health", func(c echo.Context) error { return c.JSON(http.StatusOK, map[string]interface{}{"status":"healthy","uptime":time.Since(startTime).String()}) })
	e.GET("/api/services", func(c echo.Context) error { return c.JSON(http.StatusOK, map[string]interface{}{"services":[]map[string]string{{"name":"API Gateway","status":"running"},{"name":"Database","status":"running"},{"name":"Cache","status":"running"}}}) })
	port := os.Getenv("PORT"); if port == "" { port = "1323" }; e.Logger.Fatal(e.Start(":"+port))
}
func dash() string {
	up := time.Since(startTime).Round(time.Second)
	svcs := []struct{n,s,l,i,c string}{{"API Gateway","Running","2ms","🌐","#00d4aa"},{"Database","Running","5ms","🗄️","#3b82f6"},{"Redis Cache","Running","<1ms","⚡","#f59e0b"},{"Message Queue","Running","3ms","📨","#8b5cf6"},{"Auth Service","Running","4ms","🔐","#ec4899"},{"Storage","Running","8ms","💾","#06b6d4"}}
	sh := ""; for _,s := range svcs { sh += fmt.Sprintf(`<div class="svc"><div class="si" style="background:%s18">%s</div><div class="sf"><div class="sn">%s</div><div class="ss" style="color:%s">● %s</div></div><div class="sl">%s</div></div>`,s.c,s.i,s.n,s.c,s.s,s.l) }
	bars := ""; days := []string{"Mon","Tue","Wed","Thu","Fri","Sat","Sun"}
	for i,d := range days { h:=30+rand.Intn(60); bars+=fmt.Sprintf(`<div class="bg"><div class="b" style="height:%d%%;animation-delay:%.2fs"></div><div class="bl">%s</div></div>`,h,0.3+float64(i)*0.08,d) }
	return fmt.Sprintf(`<!DOCTYPE html><html lang="en"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1.0,user-scalable=no"><title>Echo Monitor</title><style>*{margin:0;padding:0;box-sizing:border-box}:root{--bg:#080816;--card:rgba(255,255,255,0.035);--border:rgba(255,255,255,0.07);--text:#f0f0ff;--text2:rgba(240,240,255,0.55);--text3:rgba(240,240,255,0.3);--cyan:#06b6d4;--radius:14px}body{font-family:-apple-system,BlinkMacSystemFont,sans-serif;background:var(--bg);color:var(--text);min-height:100vh}.c{max-width:460px;margin:0 auto;padding:0 14px 32px;position:relative;z-index:1}.hdr{padding:20px 2px;display:flex;justify-content:space-between;align-items:center}.hdr h1{font-size:22px;font-weight:800;background:linear-gradient(135deg,#06b6d4,#22d3ee);-webkit-background-clip:text;-webkit-text-fill-color:transparent}.hdr p{font-size:12px;color:var(--text2)}.badge{font-size:11px;font-weight:600;padding:5px 12px;border-radius:20px;background:rgba(6,182,212,0.1);color:var(--cyan)}.row{display:grid;grid-template-columns:1fr 1fr 1fr;gap:10px;margin-bottom:16px}.m{background:var(--card);border:1px solid var(--border);border-radius:var(--radius);padding:14px;text-align:center}.m-val{font-size:20px;font-weight:800}.m-label{font-size:10px;color:var(--text2);text-transform:uppercase}.m:nth-child(1) .m-val{color:#00d4aa}.m:nth-child(2) .m-val{color:var(--cyan)}.m:nth-child(3) .m-val{color:#8b5cf6}.card{background:var(--card);border:1px solid var(--border);border-radius:var(--radius);padding:18px;margin-bottom:14px}.card-h{display:flex;justify-content:space-between;align-items:center;margin-bottom:14px}.card-t{font-size:15px;font-weight:700}.card-b{font-size:10px;font-weight:600;padding:3px 9px;border-radius:16px;background:rgba(6,182,212,0.1);color:var(--cyan)}.svc{display:flex;align-items:center;gap:12px;padding:10px 0;border-bottom:1px solid rgba(255,255,255,0.03)}.svc:last-child{border:none}.si{width:36px;height:36px;border-radius:10px;display:flex;align-items:center;justify-content:center;font-size:16px;flex-shrink:0}.sf{flex:1}.sn{font-size:13px;font-weight:600}.ss{font-size:11px}.sl{font-size:11px;color:var(--text3);font-family:monospace}.chart{display:flex;align-items:flex-end;justify-content:space-between;height:120px;gap:6px}.bg{flex:1;display:flex;flex-direction:column;align-items:center;gap:4px;height:100%%;justify-content:flex-end}.b{width:100%%;max-width:28px;border-radius:5px 5px 3px 3px;background:linear-gradient(180deg,#22d3ee,#0891b2);transform-origin:bottom;animation:grow .7s cubic-bezier(.34,1.56,.64,1) backwards}@keyframes grow{from{transform:scaleY(0)}to{transform:scaleY(1)}}.bl{font-size:9px;color:var(--text3)}.ft{text-align:center;padding:12px}.ft-b{font-size:10px;font-weight:600;color:var(--text3);padding:5px 12px;border-radius:20px;background:rgba(6,182,212,0.04)}@keyframes fadeIn{from{opacity:0;transform:translateY(14px)}to{opacity:1;transform:translateY(0)}}.m,.card{animation:fadeIn .5s ease backwards}</style></head><body>
<div class="c"><div class="hdr"><div><h1>📡 Echo Monitor</h1><p>Service Monitoring Panel</p></div><div class="badge">All OK</div></div>
<div class="row"><div class="m"><div class="m-val">%s</div><div class="m-label">Uptime</div></div><div class="m"><div class="m-val">6</div><div class="m-label">Services</div></div><div class="m"><div class="m-val">99.9%%</div><div class="m-label">Avail</div></div></div>
<div class="card"><div class="card-h"><span class="card-t">Services</span><span class="card-b">🟢 All Online</span></div>%s</div>
<div class="card"><div class="card-h"><span class="card-t">Traffic</span><span class="card-b">📊 Weekly</span></div><div class="chart">%s</div></div>
<div class="ft"><div class="ft-b">Echo v4 · Go 1.22 · Running</div></div></div></body></html>`,up,sh,bars)
}
